'use strict'
/**
 * import-wiktionary.cjs
 *
 * Imports Hebrew Wiktionary pages into public/wikidictionary.db.
 *
 * Input: data/hewiktionary-pages.jsonl — one JSON object per line: { title, wikitext }
 * Generated by: powershell -ExecutionPolicy Bypass -File scripts/fetch-wiktionary-api.ps1
 *
 * filter_tag: the raw layer tag from each definition (e.g. 'גס', 'סלנג', 'ספרות') is
 * stored in definition.filter_tag so filtering rules can be changed without re-importing.
 * NULL = untagged (the vast majority — always shown).
 *
 * Usage:
 *   npm run wikidict:fetch    (runs the PowerShell fetcher)
 *   npm run wikidict:import   (runs this script)
 */

const Database = require('better-sqlite3')
const fs = require('fs')
const path = require('path')

const DST_DB = path.resolve(__dirname, '../public/wikidictionary.db')
const JSONL_FILE = path.resolve(__dirname, '../data/hewiktionary-pages.jsonl')

// ── Wikitext parser (ported from useWiktionary.ts) ────────────────────────────

function stripNikud(s) {
  return s.replace(/[\u05B0-\u05C7\u05F0-\u05F4\uFB1D-\uFB4E]/g, '').trim()
}

function containsHebrew(s) {
  return /[\u05D0-\u05EA]/.test(s)
}

function cleanWiki(s) {
  return s
    .replace(/\{\{[^{}]*\}\}/g, '')
    .replace(/\{\{[^{}]*\}\}/g, '')
    .replace(/\[\[([^\]|]+\|)?([^\]]+)\]\]/g, '$2')
    .replace(/'{2,3}/g, '')
    .replace(/<ref[^>]*>[\s\S]*?<\/ref>/g, '')
    .replace(/<[^>]+>/g, '')
    .replace(/\s+/g, ' ')
    .trim()
}

function extractFromTemplate(block, key) {
  const m = block.match(new RegExp(`\\|${key}\\s*=\\s*([^\\n|]+)`))
  return m ? m[1].trim() : null
}

function extractShoresh(block) {
  const m3 = block.match(/\{\{שרש3\|([^|]+)\|([^|]+)\|([^|]+)/)
  if (m3) return `${m3[1]}-${m3[2]}-${m3[3]}`
  const m1 = block.match(/\{\{שרש\|([^|}\s]+)/)
  if (m1) return m1[1]
  return null
}

const KNOWN_SECTIONS = new Set([
  'גיזרון', 'נגזרות', 'מילים נרדפות', 'ניגודים', 'צירופים', 'מידע נוסף', 'ראו גם', 'הערות שוליים',
])

const KEEP_LANGS = new Set(['אנגלית', 'ערבית', 'ארמית'])

function parseWikitext(title, wikitext) {
  if (!wikitext || /^#הפניה|^#REDIRECT/i.test(wikitext.trim())) return []

  const lines = wikitext.split('\n')
  const senses = []
  let cur = null
  let curSection = null
  let curDefIdx = -1

  function flush() {
    if (cur && (cur.definitions.length > 0 || Object.keys(cur.sections).length > 0)) {
      senses.push(cur)
    }
    cur = null; curSection = null; curDefIdx = -1
  }

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i] || ''

    const senseMatch = line.match(/^==([^=][^=]*)==\s*$/)
    if (senseMatch) {
      flush()
      const rawHeader = (senseMatch[1] || '').replace(/\{\{[^}]*\}\}/g, '').trim()
      const nikud = /[\u05B0-\u05C7]/.test(rawHeader) ? rawHeader : null
      const headword = stripNikud(rawHeader) || stripNikud(title)
      cur = { nikud, headword, pos: null, binyan: null, shoresh: null, ktivMale: null, definitions: [], sections: {}, translations: [] }
      continue
    }

    if (!cur) continue

    if (line.includes('{{ניתוח דקדוקי')) {
      let block = line
      let j = i + 1
      let depth = (line.match(/\{\{/g) || []).length - (line.match(/\}\}/g) || []).length
      while (j < lines.length && depth > 0) {
        const nl = lines[j] || ''
        block += '\n' + nl
        depth += (nl.match(/\{\{/g) || []).length - (nl.match(/\}\}/g) || []).length
        j++
      }
      i = j - 1
      cur.shoresh = cur.shoresh || extractShoresh(block)
      cur.binyan = cur.binyan || extractFromTemplate(block, 'בניין')
      cur.pos = cur.pos || extractFromTemplate(block, 'חלק דיבר')
      cur.ktivMale = cur.ktivMale || extractFromTemplate(block, 'כתיב מלא')
      continue
    }

    const secMatch = line.match(/^===([^=]+)===\s*$/)
    if (secMatch) {
      curSection = (secMatch[1] || '').trim()
      curDefIdx = -1
      if (KNOWN_SECTIONS.has(curSection) && !cur.sections[curSection]) cur.sections[curSection] = []
      continue
    }

    if (/^====/.test(line)) { curSection = null; continue }

    if (!curSection && /^#{1,2}[^:#*]/.test(line)) {
      const layerMatch = line.match(/\{\{(?:מקרא|רובד|משלב)\|([^|}]+)/)
      const layer = layerMatch ? layerMatch[1].trim() : null
      const text = cleanWiki(line.replace(/^#+\s*/, ''))
      if (text && text.length > 1) {
        cur.definitions.push({ text, layer, examples: [] })
        curDefIdx = cur.definitions.length - 1
      }
      continue
    }

    if (!curSection && /^#[:#*]/.test(line) && curDefIdx >= 0) {
      const citMatch = line.match(/\{\{צט[^|]*\|([^|]+)\|([^|]+)\|([^|]+)\|([^|}]+)/)
      if (citMatch) {
        const src = `${citMatch[2]} ${citMatch[3]}, ${citMatch[4]}`
        const def = cur.definitions[curDefIdx]
        if (def) def.examples.push({ text: cleanWiki(citMatch[1]), source: src })
      }
      continue
    }

    if (curSection && KNOWN_SECTIONS.has(curSection)) {
      if (curSection === 'תרגום') {
        const langMatch = line.match(/^\*\s*([^:：]+)[：:]\s*(.+)/)
        if (langMatch) {
          const lang = langMatch[1].trim()
          if (KEEP_LANGS.has(lang)) {
            const words = [...(langMatch[2] || '').matchAll(/\{\{ת\|[^|]+\|([^|}]+)/g)].map(m => m[1].trim())
            if (words.length) cur.translations.push({ lang, words })
          }
        }
        continue
      }
      if (/^\*+/.test(line)) {
        const text = cleanWiki(line.replace(/^\*+\s*/, ''))
        if (text && containsHebrew(text) && text.length < 80) cur.sections[curSection].push(text)
        continue
      }
      if (line.trim() && !/^[={<[]/.test(line)) {
        const text = cleanWiki(line)
        if (text && text.length > 4) cur.sections[curSection].push(text)
      }
    }
  }

  flush()
  return senses
}

// ── Import ────────────────────────────────────────────────────────────────────

function importJsonl(jsonlPath, db) {
  const sourceId = db.prepare("SELECT id FROM source WHERE label = 'ויקימילון'").get().id

  const insertSense = db.prepare(`
    INSERT OR IGNORE INTO sense (headword, nikud, pos, binyan, shoresh, ktiv_male, etymology, source_id, sense_order)
    VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)
  `)
  const getSenseId = db.prepare('SELECT id FROM sense WHERE headword = ? AND sense_order = ? LIMIT 1')
  const insertDef = db.prepare('INSERT OR IGNORE INTO definition (sense_id, text, filter_tag, def_order) VALUES (?, ?, ?, ?)')
  const insertExample = db.prepare('INSERT OR IGNORE INTO example (definition_id, text, source) VALUES (?, ?, ?)')
  const getOrInsertSection = db.prepare('INSERT OR IGNORE INTO section (sense_id, name) VALUES (?, ?)')
  const getSectionId = db.prepare('SELECT id FROM section WHERE sense_id = ? AND name = ? LIMIT 1')
  const insertSectionItem = db.prepare('INSERT OR IGNORE INTO section_item (section_id, text, item_order) VALUES (?, ?, ?)')
  const insertTranslation = db.prepare('INSERT OR IGNORE INTO translation (sense_id, lang, word) VALUES (?, ?, ?)')

  let totalPages = 0, totalSenses = 0, totalDefs = 0, skipped = 0

  const lines = fs.readFileSync(jsonlPath, 'utf8').split('\n')
  const total = lines.length
  console.log(`Processing ${total} lines...`)

  const BATCH = 300
  let batch = []

  function processBatch(entries) {
    db.transaction(() => {
      for (const { title, wikitext } of entries) {
        if (!title || !containsHebrew(title)) { skipped++; continue }

        const parsed = parseWikitext(title, wikitext)
        if (!parsed.length) { skipped++; continue }

        totalPages++

        parsed.forEach((sense, senseOrder) => {
          const result = insertSense.run(
            sense.headword, sense.nikud, sense.pos, sense.binyan,
            sense.shoresh, sense.ktivMale, null, sourceId, senseOrder
          )
          const senseId = result.changes > 0
            ? Number(result.lastInsertRowid)
            : getSenseId.get(sense.headword, senseOrder)?.id
          if (!senseId) return

          totalSenses++

          sense.definitions.forEach((def, defOrder) => {
            const defResult = insertDef.run(senseId, def.text, def.layer || null, defOrder)
            const defId = defResult.changes > 0 ? Number(defResult.lastInsertRowid) : null
            if (defId) {
              totalDefs++
              def.examples.forEach(ex => {
                if (ex.text) insertExample.run(defId, ex.text.slice(0, 500), ex.source || null)
              })
            }
          })

          for (const [secName, items] of Object.entries(sense.sections)) {
            if (!items.length) continue
            getOrInsertSection.run(senseId, secName)
            const secId = getSectionId.get(senseId, secName)?.id
            if (secId) items.forEach((text, i) => insertSectionItem.run(secId, text, i))
          }

          sense.translations.forEach(t => {
            t.words.forEach(w => insertTranslation.run(senseId, t.lang, w))
          })
        })
      }
    })()
  }

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i].trim()
    if (!line) continue
    let obj
    try { obj = JSON.parse(line) } catch { continue }
    if (!obj.title || !obj.wikitext) continue
    batch.push(obj)
    if (batch.length >= BATCH) {
      processBatch(batch)
      batch = []
      if (i % 3000 === 0) process.stdout.write(`  ${i}/${total} lines\r`)
    }
  }
  if (batch.length) processBatch(batch)

  return { totalPages, totalSenses, totalDefs, skipped }
}

// ── Main ──────────────────────────────────────────────────────────────────────

function main() {
  if (!fs.existsSync(JSONL_FILE)) {
    console.error(`Input file not found: ${JSONL_FILE}`)
    console.error('Run first: powershell -ExecutionPolicy Bypass -File scripts/fetch-wiktionary-api.ps1')
    console.error('Or: npm run wikidict:fetch')
    process.exit(1)
  }

  console.log('Recreating schema...')
  require('./create-wikidictionary-db.cjs')

  const db = new Database(DST_DB)
  db.pragma('journal_mode = WAL')
  db.pragma('foreign_keys = ON')
  db.pragma('synchronous = NORMAL')
  db.pragma('cache_size = -32000')

  db.prepare("INSERT OR IGNORE INTO source (label) VALUES ('ויקימילון')").run()

  console.log('Importing...')
  const stats = importJsonl(JSONL_FILE, db)

  const senseCount = db.prepare('SELECT COUNT(*) as c FROM sense').get().c
  const defCount = db.prepare('SELECT COUNT(*) as c FROM definition').get().c
  const taggedCount = db.prepare('SELECT COUNT(*) as c FROM definition WHERE filter_tag IS NOT NULL').get().c
  db.close()

  console.log(`\nDone.`)
  console.log(`  Pages with Hebrew entries: ${stats.totalPages}`)
  console.log(`  Skipped: ${stats.skipped}`)
  console.log(`  Senses: ${stats.totalSenses}`)
  console.log(`  Definitions: ${stats.totalDefs}`)
  console.log(`  DB senses: ${senseCount}, definitions: ${defCount}`)
  console.log(`  Tagged definitions (filter_tag set): ${taggedCount}`)
}

main()
